            .set(HtmlAttr::Aria(AriaAttr::Live), "polite")
            .set(HtmlAttr::Aria(AriaAttr::Atomic), "false")
            .set(HtmlAttr::Aria(AriaAttr::Relevant), "additions removals")
            .set(
                HtmlAttr::Data("ars-state"),
                match self.state {
